import React, { type PropsWithChildren } from "react";
import { ResponsiveElement, useSeparator } from "../../../../Factory";
import type {IStackProps, IStyleClasses} from "@lmb-it/kitsconcerto-types";

type IsolatedStack = Omit<IStackProps, keyof IStyleClasses>

const HStack: React.FC<PropsWithChildren<IStackProps>> = (props) => {
    const { cssProps, nativeProps } = useSeparator<IStackProps>(props);
    const { space = "md", reversed = false, scrollable, children, entering, exiting, ...rest } = nativeProps;

    return (
        <ResponsiveElement<IsolatedStack>
            ref={props.ref}
            as="HStack"
            scrollable={scrollable}
            entering={entering}
            exiting={exiting}
            cssProps={cssProps}
            //@ts-ignore
            nativeProps={{
                ...rest,
                space,
                reversed,
            }}
        >
            {children}
        </ResponsiveElement>
    );
};

export default HStack;
